import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Electronics = () => {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  // 1. Admin se post kiya hua data fetch karna
  useEffect(() => {
    const fetchPosts = async () => {
      try {
        // Backend API call for 'electronics' category
        const res = await axios.get('http://localhost:5000/api/blog/electronics');
        setPosts(res.data);
      } catch (err) {
        console.error("Error fetching electronics posts:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchPosts();
  }, []);

  return (
    <div className="bg-white antialiased w-full">

      {/* 1. FULL WIDTH HEADER */}
      <section className="pt-32 pb-20 px-6 md:px-16 w-full bg-gradient-to-r from-[#1F140F] to-[#2E1A11] text-white">
        <div className="w-full">
          <h1 className="text-5xl md:text-7xl font-black tracking-tighter mb-6">
           Electronics <span className="text-orange-400">Solutions</span>
          </h1>
          <p className="text-orange-100 text-lg md:text-xl font-light max-w-3xl leading-relaxed">
            Expert staffing for power grids, industrial wiring, and renewable energy projects worldwide.
          </p>
        </div>
      </section>

      {/* 2. DYNAMIC SPOTLIGHT SECTION */}
      <section className="w-full bg-white border-t border-gray-100">
        <div className="py-16 px-6 md:px-16 w-full bg-gray-50 flex justify-between items-end">
          <div>
            <h2 className="text-5xl font-black text-gray-900 tracking-tighter">
              Industrial <span className="text-orange-600">Spotlight</span>
            </h2>
            <div className="h-1.5 w-24 bg-orange-500 mt-4 rounded-full"></div>
          </div>
          <p className="text-gray-400 font-bold uppercase text-xs tracking-widest hidden md:block">
            {posts.length} Updates Available
          </p>
        </div>

        <div className="w-full flex flex-col">
          {loading ? (
            // Loading State
            <div className="p-20 text-center text-gray-400 font-bold animate-pulse">
              Fetching latest industrial updates...
            </div>
          ) : posts.length > 0 ? (
            posts.map((post, index) => (
              <div 
                key={post._id || index} 
                className="w-full px-6 md:px-16 py-16 flex flex-col md:flex-row items-center gap-12 border-b border-gray-100 last:border-b-0 hover:bg-orange-50/30 transition-colors group"
              >
                {/* Left Side: Image from Admin */}
                <div className="flex-shrink-0">
                  <div className="h-48 w-48 bg-white border-2 border-orange-100 rounded-[2rem] flex items-center justify-center shadow-xl overflow-hidden relative group">
                    {post.image ? (
                      <img 
                        src={post.image} 
                        alt={post.title} 
                        className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                      />
                    ) : (
                      <span className="text-6xl group-hover:rotate-12 transition-transform">⚡</span>
                    )}
                    <div className="absolute inset-0 bg-orange-600/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                  </div>
                </div>

                {/* Right Side: Content */}
                <div className="flex-grow">
                  <p className="text-orange-600 font-black text-xs uppercase tracking-widest mb-2">
                    {post.date || 'LATEST UPDATE'}
                  </p>
                  <h3 className="text-3xl font-black text-gray-900 mb-4 tracking-tight group-hover:text-orange-600 transition-colors">
                    {post.title}
                  </h3>
                  <div className="relative">
                    <p className="text-gray-600 text-xl leading-relaxed max-w-5xl">
                      {post.description}
                    </p>
                  </div>
                </div>
              </div>
            ))
          ) : (
            // Empty State
            <div className="py-20 px-6 md:px-16 text-gray-400 text-xl italic">
              No industrial spotlights posted yet. Check back soon!
            </div>
          )}
        </div>
      </section>

      {/* 3. FULL WIDTH CAREER BANNER */}
      <section className="py-24 px-6 md:px-16 w-full bg-white">
        <div className="w-full bg-gradient-to-r from-orange-500 to-orange-600 rounded-[3rem] p-12 md:p-20 flex flex-col md:flex-row items-center justify-between text-white shadow-2xl shadow-orange-100">
          <div className="md:w-2/3">
            <h2 className="text-4xl md:text-6xl font-bold mb-6 tracking-tighter leading-tight">
              Start Your Career <br /> With Hudson Today
            </h2>
            <p className="text-orange-50 text-xl mb-10 max-w-xl">
              Join our global network of engineers and technicians. We're hiring for major electrical projects.
            </p>
            <Link to="/careers">
              <button className="bg-white text-orange-600 px-12 py-5 rounded-full font-bold text-xl hover:scale-105 transition-transform shadow-xl">
                Apply Now
              </button>
            </Link>
          </div>
          <div className="hidden md:flex md:w-1/3 justify-end">
            <div className="h-64 w-64 border-4 border-orange-400/30 rounded-full flex items-center justify-center animate-pulse">
               <span className="text-8xl opacity-20">⚡</span>
            </div>
          </div>
        </div>
      </section>

    </div>
  );
};

export default Electronics;
